"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[1699],{6917(t,e,d){d.r(e),d.d(e,{comp:()=>r,data:()=>i});var a=d(641);const o={},r=(0,d(6262).A)(o,[["render",function(t,e){return(0,a.uX)(),(0,a.CE)("div",null,[...e[0]||(e[0]=[(0,a.Fv)('<h1 id="design-studio" tabindex="-1"><a class="header-anchor" href="#design-studio"><span>Design Studio</span></a></h1><p><strong>Auctions → Design Studio</strong> — <code>?page=wkafw-design</code></p><p>Brand the customer-facing surfaces — bid form, countdown timer, auction badges, single-product page — with a live iframe preview. Saved values propagate site-wide.</p><p><img src="/auctions-for-woocommerce/images/screenshots/admin-design-studio-1.png" alt="Design Studio — visual presets, accent palette, typography and shape &amp; depth controls (top of page)"></p><p><img src="/auctions-for-woocommerce/images/screenshots/admin-design-studio-2.png" alt="Design Studio — density, countdown style, button presets and the live iframe preview (bottom of page)"></p><h2 id="layout" tabindex="-1"><a class="header-anchor" href="#layout"><span>Layout</span></a></h2><table><thead><tr><th>Pane</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Left</strong> — Controls</td><td>Form fields grouped by surface</td></tr><tr><td><strong>Right</strong> — Preview</td><td>Live iframe of a sample auction page; auto-refreshes on field change</td></tr><tr><td><strong>Top</strong> — Save / Reset</td><td>Apply changes site-wide; revert to defaults</td></tr></tbody></table><h2 id="surfaces-you-can-style" tabindex="-1"><a class="header-anchor" href="#surfaces-you-can-style"><span>Surfaces you can style</span></a></h2><h3 id="bid-form" tabindex="-1"><a class="header-anchor" href="#bid-form"><span>Bid form</span></a></h3><table><thead><tr><th>Field</th><th>Effect</th></tr></thead><tbody><tr><td>Background color</td><td>Bid form card background</td></tr><tr><td>Border color / radius</td><td>Card border</td></tr><tr><td>Submit button color / hover</td><td>Place Bid button</td></tr><tr><td>Quick-bid buttons enabled</td><td>Show one-click +amount buttons</td></tr><tr><td>Quick-bid amounts</td><td>CSV list of increments (e.g. <code>+10, +50, +100</code>)</td></tr><tr><td>Show bid history toggle</td><td>Display past bids inline</td></tr></tbody></table><h3 id="countdown-timer" tabindex="-1"><a class="header-anchor" href="#countdown-timer"><span>Countdown timer</span></a></h3><table><thead><tr><th>Field</th><th>Effect</th></tr></thead><tbody><tr><td>Compact / Extended layout</td><td>Single-line vs multi-line display</td></tr><tr><td>Yellow stop (<code>wkafw_countdown_yellow_s</code>)</td><td>Color flips to yellow at this many seconds</td></tr><tr><td>Orange stop</td><td>Color flips to orange</td></tr><tr><td>Red stop</td><td>Color flips to red</td></tr><tr><td>Pulse on red</td><td>Animate when in red</td></tr></tbody></table><h3 id="auction-badges" tabindex="-1"><a class="header-anchor" href="#auction-badges"><span>Auction badges</span></a></h3><p>Shop-page chips: <strong>Live / Ending Soon / New / Hot / Featured</strong>.</p><table><thead><tr><th>Field</th><th>Effect</th></tr></thead><tbody><tr><td>Live badge color</td><td>When status = active</td></tr><tr><td>Ending Soon threshold</td><td>Hours before end to flip badge</td></tr><tr><td>Hot threshold</td><td>Bids in last hour to qualify (uses <code>wkafw_hot_auction_threshold</code>)</td></tr><tr><td>Show watcher count</td><td>Display N watchers on the badge</td></tr></tbody></table><h3 id="confetti" tabindex="-1"><a class="header-anchor" href="#confetti"><span>Confetti</span></a></h3><table><thead><tr><th>Field</th><th>Effect</th></tr></thead><tbody><tr><td>Enabled (<code>wkafw_confetti_enabled</code>)</td><td>Confetti burst on win</td></tr><tr><td>Color palette</td><td>Per-customer or static</td></tr><tr><td>Duration</td><td>Animation length</td></tr></tbody></table><h3 id="single-auction-page" tabindex="-1"><a class="header-anchor" href="#single-auction-page"><span>Single auction page</span></a></h3><table><thead><tr><th>Field</th><th>Effect</th></tr></thead><tbody><tr><td>Layout</td><td>Two-column / stacked / full-width</td></tr><tr><td>Image gallery zoom</td><td>Hover-zoom enabled</td></tr><tr><td>Bid history visible</td><td>Inline / accordion / hidden</td></tr><tr><td>Watchers count visible</td><td>Show / hide</td></tr><tr><td>Reserve indicator</td><td>Show &quot;Reserve met&quot; / &quot;Not met&quot; copy</td></tr><tr><td>Share buttons</td><td>Which platforms</td></tr></tbody></table><h2 id="live-preview" tabindex="-1"><a class="header-anchor" href="#live-preview"><span>Live preview</span></a></h2><p>The preview iframe loads a synthetic auction (no real data) at <code>?wkafw_design_preview=1</code>. Every control change pushes a CSS variable update through <code>postMessage</code>; the iframe re-renders without a full reload.</p><p>To verify on a real auction:</p><ol><li>Set up your edits in Design Studio</li><li>Save</li><li>Open a real auction page in a new tab</li><li>Compare</li></ol><p>If the live page differs from the preview, check:</p><ul><li>Theme is overriding plugin styles (use <code>!important</code> sparingly in <code>your-theme/auctions-for-woocommerce/</code>)</li><li>A page-builder block is wrapping the auction (Elementor / Gutenberg may strip styles)</li><li>Caching plugin needs a flush (use <a href="/admin-tools.html#cache" target="_blank" rel="noopener noreferrer">Tools → Cache → Flush all</a>)</li></ul><h2 id="templates" tabindex="-1"><a class="header-anchor" href="#templates"><span>Templates</span></a></h2><p>For surfaces beyond what Design Studio exposes, override the source template:</p><table><thead><tr><th>Template</th><th>Used by</th></tr></thead><tbody><tr><td><code>templates/single-product/bid-form.php</code></td><td>Single auction bid form</td></tr><tr><td><code>templates/single-product/countdown.php</code></td><td>Inline countdown</td></tr><tr><td><code>templates/single-product/countdown-loop.php</code></td><td>Loop / shop countdown</td></tr><tr><td><code>templates/single-product/auction-badge.php</code></td><td>Single page badge</td></tr><tr><td><code>templates/single-product/auction-info.php</code></td><td>Auction details box</td></tr><tr><td><code>templates/single-product/bid-history.php</code></td><td>Bid history table</td></tr><tr><td><code>templates/archive/auction-badge.php</code></td><td>Shop / archive badge</td></tr><tr><td><code>templates/event-landing.php</code></td><td>Event public page</td></tr><tr><td><code>templates/leaderboard.php</code></td><td>Leaderboard widget</td></tr><tr><td><code>templates/comparison.php</code></td><td>Auction comparison page</td></tr></tbody></table><p>Copy the template to <code>your-theme/auctions-for-woocommerce/{path}</code> to override.</p><h2 id="css-variables" tabindex="-1"><a class="header-anchor" href="#css-variables"><span>CSS variables</span></a></h2><p>The plugin exposes design tokens as CSS variables. Override in <code>style.css</code>:</p><p>Variables apply to every auction surface via the <code>.wkafw-*</code> class scope.</p><h2 id="reset-to-defaults" tabindex="-1"><a class="header-anchor" href="#reset-to-defaults"><span>Reset to defaults</span></a></h2><p><strong>Reset</strong> at the top of the page wipes all design settings back to the bundled defaults. Useful when you want a clean restart.</p><h2 id="saving" tabindex="-1"><a class="header-anchor" href="#saving"><span>Saving</span></a></h2><p>Saved values are written to:</p><table><thead><tr><th>Option</th><th>What</th></tr></thead><tbody><tr><td><code>wkafw_design_settings</code></td><td>JSON blob of all design fields</td></tr><tr><td><code>wkafw_countdown_yellow_s</code> / <code>_orange_s</code> / <code>_red_s</code></td><td>Countdown thresholds (separate options for legacy compat)</td></tr><tr><td><code>wkafw_confetti_enabled</code></td><td>Boolean toggle</td></tr></tbody></table>',37)])])}]]),i=JSON.parse('{"path":"/admin-design-studio.html","title":"Design Studio","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"Layout","slug":"layout","link":"#layout","children":[]},{"level":2,"title":"Surfaces you can style","slug":"surfaces-you-can-style","link":"#surfaces-you-can-style","children":[{"level":3,"title":"Bid form","slug":"bid-form","link":"#bid-form","children":[]},{"level":3,"title":"Countdown timer","slug":"countdown-timer","link":"#countdown-timer","children":[]},{"level":3,"title":"Auction badges","slug":"auction-badges","link":"#auction-badges","children":[]},{"level":3,"title":"Confetti","slug":"confetti","link":"#confetti","children":[]},{"level":3,"title":"Single auction page","slug":"single-auction-page","link":"#single-auction-page","children":[]}]},{"level":2,"title":"Live preview","slug":"live-preview","link":"#live-preview","children":[]},{"level":2,"title":"Templates","slug":"templates","link":"#templates","children":[]},{"level":2,"title":"CSS variables","slug":"css-variables","link":"#css-variables","children":[]},{"level":2,"title":"Reset to defaults","slug":"reset-to-defaults","link":"#reset-to-defaults","children":[]},{"level":2,"title":"Saving","slug":"saving","link":"#saving","children":[]}],"git":{},"filePathRelative":"admin-design-studio.md"}')}}]);